local Junkie = loadstring(game:HttpGet("https://jnkie.com/sdk/library.lua"))()
Junkie.service = "soso"
Junkie.identifier = 1002451
Junkie.provider = "sosot"

local repo = "https://raw.githubusercontent.com/deividcomsono/Obsidian/main/"
loadstring(game:HttpGet('https://raw.githubusercontent.com/EdgeIY/infiniteyield/master/source'))()
local Library = loadstring(game:HttpGet(repo .. "Library.lua"))()
local SaveManager = loadstring(game:HttpGet(repo .. "addons/SaveManager.lua"))()
local ThemeManager = loadstring(game:HttpGet(repo .. "addons/ThemeManager.lua"))()
local Options = Library.Options
local Toggles = Library.Toggles

local UserKey
local result

if not isfolder("POSRALBOOST") then makefolder("POSRALBOOST") end
if isfolder("POSRALBOOST") and isfile("POSRALBOOST/PosralKey.posral") then
    local va = Junkie.check_key(readfile("POSRALBOOST/PosralKey.posral"))
    if va.valid == true then
        UserKey = readfile("POSRALBOOST/PosralKey.posral")
        result = true
    end
end

local Window = Library:CreateWindow({
    Title = "Posral Loader",
    Footer = "version: РРґРё РЅР°С…СѓР№ РЅРµ С‡РёС‚Р°Р№",
    NotifySide = "Right",
})

local Tabs = {
	Main = Window:AddTab("Main"),
	["UI Settings"] = Window:AddTab("UI Settings"),
}
local box = Tabs.Main:AddLeftGroupbox("Key System")
box:AddInput("KeySys", {
	Default = "Key",
	Numeric = false, -- true / false, only allows numbers
	Finished = false, -- true / false, only calls callback when you press enter
	ClearTextOnFocus = true, -- true / false, if false the text will not clear when textbox focused

	Text = "Key",
	Tooltip = "Insert Your Key", -- Information shown when you hover over the textbox

	Placeholder = "xxxxxxxxxxxxx", -- placeholder text when the box is empty

	Callback = function(v)
		UserKey = v
        print(UserKey)
	end,
})

box:AddButton("Check Key", function()
    print(UserKey)
    local val = Junkie.check_key(UserKey)
    if val.valid ~= true then
        return Library:Notify({
            Title = "Posral",
            Description = "Invalid Key!",
            Time = 4,
        })
    end
    writefile("POSRALBOOST/PosralKey.posral", UserKey)
    Library:Notify({
        Title = "Posral",
        Description = "Correct Key!",
        Time = 4,
    })
    result = true
end)

box:AddButton("Get Key", function()
    local link, err = Junkie.get_key_link()
    setclipboard(link)
    Library:Notify({
        Title = "Posral",
        Description = "Key Link Copied To your clipboard",
        Time = 4,
    })
end)
box:AddDivider()
box:AddDivider("Tired of Keys?")
box:AddButton("Copy FunPay Link", function() Library:Notify("Link Copied to Clipboard!") setclipboard("https://funpay.com/lots/offer?id=63841928") end)
box:AddDivider()
box:AddDivider("Need Help?")
box:AddButton("Copy Discord Link", function() Library:Notify("Link Copied to Clipboard!") setclipboard("https://discord.gg/posral") end)

local MenuGroup = Tabs["UI Settings"]:AddLeftGroupbox("Menu Settings")

MenuGroup:AddButton("Unload", function()
    for i,v in Toggles do
        if not v.Value then continue end
        v:SetValue(false)
    end
	Library:Unload()
end)

MenuGroup:AddLabel("Menu bind"):AddKeyPicker("MenuKeybind", {
    Default = "X",
    NoUI = false,
    Text = "Menu keybind"
})

MenuGroup:AddToggle("AlwaysViewCursor", {
    Text = "Always View Cursor",
    Default = false,
    Callback = function(v)
        alwaysshowcursor = v
        if v then
            task.spawn(function()
                while alwaysshowcursor and task.wait() do
                    game.UserInputService.MouseIconEnabled = true
                end
            end)
        else
            game.UserInputService.MouseIconEnabled = false
        end
    end
})

Library.ToggleKeybind = Options.MenuKeybind 

ThemeManager:SetLibrary(Library)

ThemeManager:SetFolder("MyScriptHub")

ThemeManager:ApplyToTab(Tabs["UI Settings"])

ThemeManager:LoadDefault()

SaveManager:SetLibrary(Library)

SaveManager:IgnoreThemeSettings()

SaveManager:SetIgnoreIndexes({ "MenuKeybind" })

SaveManager:SetFolder("MyScriptHub/specific-game")

SaveManager:BuildConfigSection(Tabs["UI Settings"])

SaveManager:LoadAutoloadConfig()

while result ~= true do task.wait() end
getgenv().SCRIPT_KEY = UserKey
Library:Unload()
print(getgenv().SCRIPT_KEY)
print('soso')

